# DK LTY.  Lemvig - Thyborøn
#
let lt = path("d3.dk.lty");

with detail = 3, railway = :first :pax {
    # point.dk.Lemvig  dk.VLV

    with link = "line.dk.LTY" {
        track(:lor,
                lt[:lem.yt - 0.1dl, :lem.yt] >> 1ms >> 1mt
            ..  lt[:lem.xt + 2mt, :lem.xt + 2.1mt]
        );
        track(lt[:lem.xt + 2mt, :lem.xt + 1.21km]);
        line_label(:right:s, lt[:lem.xt + 1.2km] >> 0.5mt, "LTY");
        track(lt[:lem.xt + 1.19km, :bal - 0.49sw]);
    }

    with link = "point.dk.Balleby", railway = :station {
        track(lt[:bal - 0.5sw, :bal + 0.5sw]);
        marker(:right :de.hp, lt[:bal] >> 0.5mt);
        slabel(:top, lt[:bal] >> 0.5mt >> 1sh >> 0.2dt, "Balleby");
    }

    with link = "line.dk.LTY" {
        track(lt[:bal + 0.49sw, :hou - 0.49sw]);
    }

    with link = "point.dk.Houmaa", railway = :station {
        track(lt[:hou - 0.5sw, :hou + 0.5sw]);
        marker(:left :de.hp :removed, lt[:hou] << 0.5mt);
        slabel(:left :removed, lt[:hou] << 0.5mt << 1sh + (-1.4dt, 1.1dt),
            "Houmaa"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:hou + 0.49sw, :kli - 0.49sw]);
    }

    with link = "point.dk.Klinkby", railway = :station {
        track(lt[:kli - 0.5sw, :kli + 0.5sw]);
        marker(:right :de.hp, lt[:kli] >> 0.5mt);
        marker(:right :de.exbf, lt[:kli] >> 0.5mt);
        slabel(:right, lt[:kli] >> 0.5mt >> 1.4sh + (1.4dt, 0.9dt), "Klinkby");
    }

    with link = "line.dk.LTY" {
        track(lt[:kli + 0.49sw, :nej - 0.49sw]);
    }

    with link = "point.dk.Nejrup", railway = :station {
        track(lt[:nej - 0.5sw, :nej + 0.5sw]);
        marker(:left :de.hp, lt[:nej] << 0.5mt);
        slabel(:bottom, lt[:nej] << 0.5mt << 1sh << 0.3dt,
            "Nejrup"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:nej + 0.49sw, :str - 0.49sw]);
    }

    with link = "point.dk.Strande", railway = :station {
        track(lt[:str - 0.5sw, :str + 0.5sw]);
        marker(:left :de.bf, lt[:str] << 0.5mt);
        slabel(:bottom, lt[:str] << 0.5mt << 1sh + (-0.5dt, 0.2dt),
            "Strande"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:str + 0.49sw, :vic - 0.49sw]);
    }

    with link = "point.dk.Victoria-Street-Station", railway = :station {
        track(lt[:vic - 0.5sw, :vic + 0.5sw]);
        marker(:left :de.hp, lt[:vic] << 0.5mt);
        slabel(:left, lt[:vic] << 0.5mt << 1sh + (-1.2dt, 1.1dt),
            "Victoria Street Station*"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:vic + 0.49sw, :ven - 0.49sw]);
    }

    with link = "point.dk.Vejlby-Nord", railway = :station {
        track(lt[:ven - 0.5sw, :ven + 0.5sw]);
        marker(:left :de.hp :removed, lt[:ven] << 0.5mt);
        slabel(:left :removed, lt[:ven] << 0.5mt << 1sh + (-1.2dt, 1.1dt),
            "Vejlby Nord"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:ven + 0.49sw, :vri - 0.49sw]);
    }

    with link = "point.dk.Vrist", railway = :station {
        track(lt[:vri - 0.5sw, :vri + 0.5sw]);
        marker(:left :de.hp, lt[:vri] << 0.5mt);
        marker(:left :de.exbf, lt[:vri] << 0.5mt);
        slabel(:left, lt[:vri] << 0.5mt << 1.4sh + (-1.4dt, 0.9dt),
            "Vrist"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:vri + 0.49sw, :har - 0.49sw]);
    }

    with link = "point.dk.Harboøre", railway = :station {
        track(lt[:har - 0.5sw, :har + 0.5sw]);
        marker(:right :de.bf, lt[:har] >> 0.5mt);
        slabel(:right, lt[:har] >> 0.5mt >> 1sh + (1.6dt, 1.7dt),
            "Harboøre"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:har + 0.49sw, :har.yt]);
        track(lt[:har.yt - 0.1dl, :ron - 0.49sw]);
    }

    with link = "point.dk.Rønland", railway = :station {
        track(lt[:ron - 0.5sw, :ron + 0.5sw]);
        marker(:right :de.bf, lt[:ron] >> 0.5mt);
        slabel(:right, lt[:ron] >> 0.5mt >> 1sh + (1.3dt, 1.2dt),
            "Rønland"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:ron + 0.49sw, :ron + 2.21km]);
        line_label(:right:nw, lt[:ron + 2.2km] >> 0.5mt, "LTY");
        track(lt[:ron + 2.19km, :thf - 0.49sw]);
    }

    with link = "point.dk.Thyborøn-Færge", railway = :station {
        track(lt[:thf - 0.5sw, :thf + 0.5sw]);
        marker(:right :de.hp :removed, lt[:thf] >> 0.5mt);
        slabel(:right :removed, lt[:thf] >> 0.5mt >> 1sh + (1.2dt, 1dt),
            "Thyborøn Færge"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:thf + 0.49sw, :spr - 0.49sw]);
    }

    with link = "point.dk.Sprogøvej", railway = :station {
        track(lt[:spr - 0.5sw, :spr + 0.5sw]);
        marker(:right :de.hp, lt[:spr] >> 0.5mt);
        slabel(:right, lt[:spr] >> 0.5mt >> 1sh + (1.5dt, 1dt),
            "Sprogøvej"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:spr + 0.49sw, :thk - 0.49sw]);
    }

    with link = "point.dk.Thyborøn-Kirke", railway = :station {
        track(lt[:thk - 0.5sw, :thk + 0.5sw]);
        marker(:right :de.hp, lt[:thk] >> 0.5mt);
        slabel(:right, lt[:thk] >> 0.5mt >> 1sh + (1.3dt, 0.8dt),
            "Thyborøn Kirke"
        );
    }

    with link = "line.dk.LTY" {
        track(lt[:thk + 0.49sw, :thh.yl + 0.1dl]);
        track(lt[:thh.yl + 0.1dl, :thh - 0.49sw]);
    }

    with link = "point.dk.Thyborøn-Havn", railway = :station {
        track(lt[:thh - 0.5sw, :thh.f]);
        marker(:left :de.bf, lt[:thh] << 0.5mt);
        slabel(:left :bold, lt[:thh] << 0.5mt << 1sh + (-1.5dt, 0.3dt),
            "Thyborøn Havn"
        );
    }
}

with detail = 3, railway = :first :pax :removed {
    let ht = path("d3.dk.lty.kno");

    with link = "line.dk.LTY" {
        track(ht[:har.yt, :lan - 0.49sw]);
    }

    with link = "point.dk.Langerhuse", railway = :station {
        track(ht[:lan - 0.5sw, :lan + 0.5sw]);
        marker(:right :de.hp, ht[:lan] >> 0.5mt);
        slabel(:ne, ht[:lan] << 0.5mt + (-1dt, -1dt),
            "Langerhuse"
        );
    }

    with link = "line.dk.LTY" {
        track(ht[:lan + 0.49sw, :kno - 0.49sw]);
    }

    with link = "point.dk.Knopper", railway = :station {
        track(ht[:kno - 0.5sw, :kno + 0.5sw]);
        marker(:right :de.bf, ht[:kno] >> 0.5mt);
        slabel(:left, ht[:kno] << 0.5mt + (-1.3dt, 1dt),
            "Knopper"
        );
    }

    with link = "line.dk.LTY" {
        track(ht[:kno + 0.49sw, :kno + 2.51km]);
        line_label(:left:e, ht[:kno + 2.5km] << 0.5mt, (0dt, -0.2dt), "LTY");
        track(ht[:kno + 2.49km, :thk - 0.49sw]);
    }

    with link = "point.dk.Thyborøn-Kirke", railway = :station {
        track(ht[:thk - 0.5sw, :thh.yl]);
        marker(:left :de.hp, ht[:thk] << 0.5mt);
        marker(:left :de.exbf, ht[:thk] << 0.5mt);
        slabel(:left, ht[:thk] << 0.5mt << 1.4sh + (-0.8dt, 0.6dt),
            "Thyborøn Kirke*"
        );
    }
}

